  primary: '#E74C3C',
  secondary: '#3498DB',
  success: '#27AE60',
  warning: '#F39C12',
  danger: '#C0392B',
  light: '#ECF0F1',
  dark: '#2C3E50',
  white: '#FFFFFF',
  gray: '#95A5A6',
  lightGray: '#BDC3C7',
};

export const Sizes = {
  xs: 4,
  sm: 8,
  md: 16,
  lg: 24,
  xl: 32,
  xxl: 48,
};

